import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate, Link } from 'react-router-dom';
import { loginUser } from '../redux/thunks/authThunks';
import { clearError } from '../redux/slices/authSlice';
import { toast } from 'react-toastify';
import './Login.css';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [emailError, setEmailError] = useState(false);
  const [passwordError, setPasswordError] = useState(false);

  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { loading, error } = useSelector((state) => state.auth);

  useEffect(() => {
    if (error) {
      toast.error(error);
      dispatch(clearError());
    }
  }, [error, dispatch]);

  const validateEmail = (val) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val);
  };

  const handleLogin = (e) => {
    e.preventDefault();
    let valid = true;

    if (!email || !validateEmail(email)) {
      setEmailError(true);
      valid = false;
    } else {
      setEmailError(false);
    }

    if (!password || password.length < 6) {
      setPasswordError(true);
      valid = false;
    } else {
      setPasswordError(false);
    }

    if (!valid) {
      toast.warn('Please enter valid email and password (min 6 characters)');
      return;
    }

    dispatch(loginUser({ email, password }));
  };

  return (
    <div className="login-screen">
      <div className="login-container">
        <div className="login-logo-section">
          <div className="login-logo">FL</div>
          <h1 className="login-title">FriendLinq</h1>
        </div>

        <form onSubmit={handleLogin} className="login-form">
          <input
            type="email"
            className={`login-input ${emailError ? 'input-error' : ''}`}
            placeholder="Email"
            value={email}
            onChange={(e) => { setEmail(e.target.value); setEmailError(false); }}
            autoComplete="email"
          />

          <div className={`login-password-wrap ${passwordError ? 'input-error' : ''}`}>
            <input
              type={showPassword ? 'text' : 'password'}
              className="login-password-input"
              placeholder="Password"
              value={password}
              onChange={(e) => { setPassword(e.target.value); setPasswordError(false); }}
              autoComplete="current-password"
            />
            <button
              type="button"
              className="login-eye-btn"
              onClick={() => setShowPassword(!showPassword)}
              aria-label="Toggle password visibility"
            >
              {showPassword ? '👁' : '👁‍🗨'}
            </button>
          </div>

          <div className="login-forgot-row">
            <Link to="/forgot-password" className="login-forgot-link">
              Forgot Password
            </Link>
          </div>

          <button
            type="submit"
            className="login-btn-primary"
            disabled={loading}
          >
            {loading ? 'Logging in...' : 'Login'}
          </button>

          <button
            type="button"
            className="login-btn-secondary"
            onClick={() => navigate('/register')}
          >
            Sign Up
          </button>
        </form>

        <p className="login-footer-text">
          Join others finding connections on FriendLinq
        </p>
      </div>
    </div>
  );
};

export default Login;
